import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'

ChartJS.register(...registerables);

class Report extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedYear: [], selectedProgram: [], selectedCategory: [], chartResultData: [], selectedType: []
        };
    }

    handleYearChange = (selectedOptions) => {
        this.setState({selectedYear: selectedOptions})
      }

      handleProgramChange = (selectedOptions) => {
        this.setState({selectedProgram: selectedOptions})
      }

      handleCategoryChange = (selectedOptions) => {
        this.setState({selectedCategory: selectedOptions})
      }

      handleTypeChange = (selectedOptions) => {
        this.setState({selectedType: selectedOptions})
      }


      handleSubmit = () => {
      this.setState({screen: 0});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');


      var backUrl = properties.backend + `getEducationData`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({year: this.state.selectedYear, category: this.state.selectedCategory, program: this.state.selectedProgram, type: this.state.selectedType})

      })
      .then(response => response.json())
      .then(response => {
        this.setState({chartResultData: response})
        this.setState({screen: 1})
        //this.setState({selectedYear: []})
        //this.setState({selectedCategory: []})
        //this.setState({selectedProgram: []})
      })
      .catch(err => {
        console.log(err);
      });

    }

      componentDidMount() {



        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `educationOption`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }






          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []


              const yearOptions = []

                this.state.results.year.map(rec => {
                    yearOptions.push({value: rec.survey_year, label: rec.survey_year})
                })

                const programOptions = []

                this.state.results.program.map(rec => {
                    programOptions.push({value: rec.id, label: rec.name})
                })


                const categoryOptions = [] 

                this.state.results.category.map(rec => {
                    categoryOptions.push({value: rec.category, label: rec.category})
                })

                const typeOptions = [] 

                this.state.results.type.map(rec => {
                    typeOptions.push({value: rec.surveytype, label: rec.surveytype})
                })



                content.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="year" value={this.state.selectedYear} options={yearOptions} onChange={this.handleYearChange}/></div>)
                content.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="program" value={this.state.selectedProgram} options={programOptions} onChange={this.handleProgramChange}/></div>)
                content.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="category" value={this.state.selectedCategory} options={categoryOptions} onChange={this.handleCategoryChange}/></div>)
                content.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="type" value={this.state.selectedType} options={typeOptions} onChange={this.handleTypeChange}/></div>)



                content.push(<div style={{textAlign: "center", marginTop: "15px"}}><button onClick={() => this.handleSubmit()}  id="submit" style={{height: "40px", width: "220px", fontSize: "16px", backgroundColor: "yellow" }}>Submit</button></div>)


          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Report
